// Classify incoming trigger:
//   - Schedule cron: mode='rotate', no filter
//   - /webhook/ab-test/rotate: mode='rotate', optional ab_test_id
//   - /webhook/ab-test/start: mode='start', needs { topic_id, test_type, variants[] }
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const hasBody = !!raw.body;
const payload = raw.body || {};

// Distinguish between /ab-test/rotate and /ab-test/start via webhookUrl (n8n exposes this on raw)
const webhookPath = raw.webhookUrl || raw.headers?.['x-webhook-path'] || '';
const isStart = hasBody && (payload.test_type || payload.topic_id && Array.isArray(payload.variants));
const isRotate = hasBody && !isStart;
const isCron = !hasBody;

const mode = isStart ? 'start' : 'rotate';

return [{
  json: {
    mode,
    via_webhook: hasBody,
    via_cron: isCron,
    payload,
    triggered_at: new Date().toISOString()
  }
}];

// CF17 — start path. Insert ab_tests + ab_test_variants, apply variant 0 to YouTube.
// YouTube OAuth via $env.YOUTUBE_OAUTH_TOKEN (pre-obtained bearer; TODO: full refresh-token flow).
// If OAuth missing, skip videos.update and return — test rows still created for DB-only tracking.

const data = $input.first().json;
if (data.mode !== 'start') return $input.item;
const p = data.payload || {};

const topicId = p.topic_id;
const testType = p.test_type; // 'title' | 'thumbnail' | 'combined'
const variants = Array.isArray(p.variants) ? p.variants : [];

if (!topicId || !testType || variants.length < 2) {
  return [{ json: { success: false, error: 'Provide { topic_id, test_type, variants: [>=2] }', http_status: 400, via_webhook: true } }];
}
if (!['title', 'thumbnail', 'combined'].includes(testType)) {
  return [{ json: { success: false, error: 'test_type must be title|thumbnail|combined', http_status: 400, via_webhook: true } }];
}
if (variants.length > 5) {
  return [{ json: { success: false, error: 'Max 5 variants per test', http_status: 400, via_webhook: true } }];
}

const minImp = Number(p.min_impressions_per_variant) || 1000;
const minDays = Number(p.min_days_per_variant) || 2;
const rotationHours = Number(p.rotation_interval_hours) || 48;
const confThresh = Number(p.confidence_threshold) || 0.95;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytOauth = $env.YOUTUBE_OAUTH_TOKEN; // TODO: wire full OAuth2 credential refresh

// 1. Fetch topic for project_id + youtube_video_id
const topicRes = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,youtube_video_id,seo_title,selected_title,thumbnail_url`, {
  method: 'GET', headers: sbHeaders
});
if (!topicRes.ok) return [{ json: { success: false, error: `Topic fetch failed: ${topicRes.status}`, http_status: 500, via_webhook: true } }];
const tArr = await topicRes.json();
const topic = Array.isArray(tArr) && tArr[0] ? tArr[0] : null;
if (!topic) return [{ json: { success: false, error: `Topic ${topicId} not found`, http_status: 404, via_webhook: true } }];
if (!topic.youtube_video_id) return [{ json: { success: false, error: 'Topic has no youtube_video_id — publish to YouTube before starting A/B test', http_status: 400, via_webhook: true } }];

const projectId = topic.project_id;
const youtubeVideoId = topic.youtube_video_id;
const nowIso = new Date().toISOString();

// 2. Insert ab_tests row
let abTestId = null;
try {
  const insRes = await fetch(`${supabaseUrl}/rest/v1/ab_tests`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify({
      topic_id: topicId,
      project_id: projectId,
      youtube_video_id: youtubeVideoId,
      test_type: testType,
      status: 'running',
      min_impressions_per_variant: minImp,
      min_days_per_variant: minDays,
      rotation_interval_hours: rotationHours,
      confidence_threshold: confThresh,
      started_at: nowIso,
      last_rotated_at: nowIso
    })
  });
  if (!insRes.ok) return [{ json: { success: false, error: `ab_tests insert: ${insRes.status}: ${(await insRes.text()).slice(0, 200)}`, http_status: 500, via_webhook: true } }];
  const arr = await insRes.json();
  abTestId = arr[0]?.id;
} catch (e) {
  return [{ json: { success: false, error: `ab_tests insert threw: ${e.message}`, http_status: 500, via_webhook: true } }];
}

// 3. Insert variants
const labels = ['A', 'B', 'C', 'D', 'E'];
const variantRows = variants.map((v, idx) => ({
  ab_test_id: abTestId,
  variant_label: labels[idx],
  variant_order: idx,
  title: v.title || null,
  thumbnail_url: v.thumbnail_url || null,
  thumbnail_drive_id: v.thumbnail_drive_id || null,
  predicted_ctr_score: v.predicted_ctr_score || null
}));

let variantIds = [];
try {
  const vRes = await fetch(`${supabaseUrl}/rest/v1/ab_test_variants`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify(variantRows)
  });
  if (!vRes.ok) return [{ json: { success: false, error: `variants insert: ${vRes.status}: ${(await vRes.text()).slice(0, 200)}`, http_status: 500, ab_test_id: abTestId, via_webhook: true } }];
  variantIds = (await vRes.json()).map(r => r.id);
} catch (e) {
  return [{ json: { success: false, error: `variants insert threw: ${e.message}`, http_status: 500, ab_test_id: abTestId, via_webhook: true } }];
}

// 4. Pick variant 0 as current, PATCH ab_tests.current_variant_id
const currentVariantId = variantIds[0];
try {
  await fetch(`${supabaseUrl}/rest/v1/ab_tests?id=eq.${abTestId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ current_variant_id: currentVariantId })
  });
  // Mark variant 0 as live
  await fetch(`${supabaseUrl}/rest/v1/ab_test_variants?id=eq.${currentVariantId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ last_live_at: nowIso, rotation_count: 1 })
  });
} catch (_) { }

// 5. Apply variant 0 to YouTube (videos.update)
let applyError = null;
let youtubeApplied = false;
if (ytOauth) {
  try {
    // Fetch current video metadata first (to preserve snippet fields we don't change)
    const getRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet&id=${youtubeVideoId}`, {
      method: 'GET',
      headers: { 'Authorization': `Bearer ${ytOauth}` }
    });
    if (getRes.ok) {
      const body = await getRes.json();
      const snippet = body.items?.[0]?.snippet || {};
      const firstVariant = variants[0] || {};
      if ((testType === 'title' || testType === 'combined') && firstVariant.title) {
        snippet.title = firstVariant.title.slice(0, 100);
      }
      // categoryId is required by YouTube API on snippet update; preserve if present, else default to '22' (People & Blogs)
      if (!snippet.categoryId) snippet.categoryId = '22';

      const updRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${ytOauth}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ id: youtubeVideoId, snippet })
      });
      if (!updRes.ok) applyError = `videos.update: HTTP ${updRes.status}: ${(await updRes.text()).slice(0, 200)}`;
      else youtubeApplied = true;

      // Thumbnail upload requires videos/thumbnails endpoint with binary — TODO: implement when OAuth refresh is wired.
      if (youtubeApplied && (testType === 'thumbnail' || testType === 'combined') && firstVariant.thumbnail_url) {
        // TODO: POST binary to https://www.googleapis.com/upload/youtube/v3/thumbnails/set?videoId={id}
        // Needs fetching thumbnail_url -> binary body -> upload with correct content-type.
      }
    } else {
      applyError = `videos.list: HTTP ${getRes.status}`;
    }
  } catch (e) {
    applyError = e.message;
  }
} else {
  applyError = 'YOUTUBE_OAUTH_TOKEN not set — recorded in DB only. TODO: operator configures OAuth refresh flow.';
}

return [{
  json: {
    success: true,
    mode: 'start',
    ab_test_id: abTestId,
    topic_id: topicId,
    project_id: projectId,
    youtube_video_id: youtubeVideoId,
    test_type: testType,
    status: 'running',
    current_variant_id: currentVariantId,
    variant_count: variantIds.length,
    youtube_applied: youtubeApplied,
    apply_error: applyError,
    http_status: 200,
    via_webhook: true
  }
}];

// CF17 — rotate path. Cron + manual. For each running ab_test:
//   1. Pull YouTube Analytics for current variant window
//   2. Update cumulative totals on ab_test_variants
//   3. Insert ab_test_impressions snapshot
//   4. Pick next variant, apply to YouTube, patch ab_tests
//   5. Check winner: if all variants meet min_impressions+min_days, run two-proportion z-test
// Inline backoff. Batch 3 tests per run.

const data = $input.first().json;
if (data.mode !== 'rotate') return $input.item;
const p = data.payload || {};
const specificTestId = p.ab_test_id || null;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytOauth = $env.YOUTUBE_OAUTH_TOKEN; // TODO: full OAuth2 refresh
const ytChannelId = $env.YOUTUBE_CHANNEL_ID; // required for analytics ids=channel==X

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), attempts: attempt };
      const body = await res.text();
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// Two-proportion z-test for winner determination
function twoPropZ(x1, n1, x2, n2) {
  if (n1 <= 0 || n2 <= 0) return 0;
  const p1 = x1 / n1, p2 = x2 / n2;
  const pPool = (x1 + x2) / (n1 + n2);
  const se = Math.sqrt(pPool * (1 - pPool) * (1 / n1 + 1 / n2));
  if (se === 0) return 0;
  return (p1 - p2) / se;
}

// Approximate normal CDF -> confidence
function normalCdf(z) {
  // Abramowitz & Stegun 26.2.17 approximation
  const b1 = 0.319381530, b2 = -0.356563782, b3 = 1.781477937, b4 = -1.821255978, b5 = 1.330274429;
  const p = 0.2316419, c = 0.39894228;
  const absZ = Math.abs(z);
  const t = 1 / (1 + p * absZ);
  const val = c * Math.exp(-absZ * absZ / 2) * (t * (b1 + t * (b2 + t * (b3 + t * (b4 + t * b5)))));
  return z >= 0 ? 1 - val : val;
}

// 1. Load running tests
let testUrl = `${supabaseUrl}/rest/v1/ab_tests?status=eq.running&select=*&order=last_rotated_at.asc.nullsfirst&limit=3`;
if (specificTestId) testUrl = `${supabaseUrl}/rest/v1/ab_tests?id=eq.${specificTestId}&status=eq.running&select=*`;

const testsRes = await fetch(testUrl, { method: 'GET', headers: sbHeaders });
if (!testsRes.ok) return [{ json: { success: false, error: `fetch ab_tests: ${testsRes.status}`, http_status: 500, via_webhook: data.via_webhook } }];
const tests = await testsRes.json();

if (tests.length === 0) {
  return [{ json: { success: true, mode: 'rotate', message: 'No running tests need rotation', rotated: 0, http_status: 200, via_webhook: data.via_webhook } }];
}

const results = [];
const nowMs = Date.now();
const nowIso = new Date().toISOString();

for (const test of tests) {
  const testResult = { ab_test_id: test.id, rotated: false, winner_found: false, errors: [] };

  // Check rotation interval
  const lastRot = test.last_rotated_at ? new Date(test.last_rotated_at).getTime() : 0;
  const hoursSinceRot = (nowMs - lastRot) / 3600000;
  const intervalHrs = test.rotation_interval_hours || 48;
  const forceRotate = !!p.force || !!specificTestId;
  if (!forceRotate && hoursSinceRot < intervalHrs) {
    testResult.skipped = `Only ${hoursSinceRot.toFixed(1)}h since last rotation (interval=${intervalHrs}h)`;
    results.push(testResult);
    continue;
  }

  // 2. Load variants for this test
  const vRes = await fetch(`${supabaseUrl}/rest/v1/ab_test_variants?ab_test_id=eq.${test.id}&select=*&order=variant_order.asc`, {
    method: 'GET', headers: sbHeaders
  });
  if (!vRes.ok) { testResult.errors.push(`fetch variants: ${vRes.status}`); results.push(testResult); continue; }
  const variants = await vRes.json();
  if (variants.length < 2) { testResult.errors.push('fewer than 2 variants'); results.push(testResult); continue; }

  const currentVariant = variants.find(v => v.id === test.current_variant_id) || variants[0];

  // 3. Pull YouTube Analytics for current variant's window
  let deltaImp = 0, deltaViews = 0, windowStart = null, windowEnd = nowIso, analyticsOk = false;
  if (ytOauth && ytChannelId && test.youtube_video_id) {
    const windowStartMs = currentVariant.last_live_at ? new Date(currentVariant.last_live_at).getTime() : lastRot || nowMs - (intervalHrs * 3600000);
    const startDate = new Date(windowStartMs).toISOString().slice(0, 10);
    const endDate = nowIso.slice(0, 10);
    windowStart = new Date(windowStartMs).toISOString();

    // TODO: YouTube Analytics API requires full OAuth2 scope 'https://www.googleapis.com/auth/yt-analytics.readonly'
    const analyticsUrl = `https://youtubeanalytics.googleapis.com/v2/reports?ids=channel==${encodeURIComponent(ytChannelId)}&metrics=views,impressions,estimatedMinutesWatched&filters=video==${test.youtube_video_id}&startDate=${startDate}&endDate=${endDate}`;
    const aRes = await fetchWithRetry(analyticsUrl, {
      method: 'GET',
      headers: { 'Authorization': `Bearer ${ytOauth}` }
    }, 'yt_analytics');
    if (aRes.ok) {
      const rows = aRes.json?.rows || [];
      if (rows.length > 0) {
        const [views, impressions /* , minutes */] = rows[0];
        deltaViews = Number(views) || 0;
        deltaImp = Number(impressions) || 0;
        analyticsOk = true;
      } else {
        testResult.errors.push('analytics returned 0 rows — no data yet');
      }
    } else {
      testResult.errors.push(`analytics ${aRes.status || ''}: ${(aRes.error || '').slice(0, 100)}`);
    }
  } else {
    testResult.errors.push('YOUTUBE_OAUTH_TOKEN or YOUTUBE_CHANNEL_ID missing — rotating blind. TODO: wire OAuth refresh.');
  }

  // 4. Insert impressions snapshot + update variant cumulatives (even if analytics failed — keeps timeline)
  if (analyticsOk) {
    try {
      await fetch(`${supabaseUrl}/rest/v1/ab_test_impressions`, {
        method: 'POST', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          ab_test_variant_id: currentVariant.id,
          ab_test_id: test.id,
          snapshot_at: nowIso,
          window_start: windowStart,
          window_end: windowEnd,
          impressions: deltaImp,
          views: deltaViews,
          ctr: deltaImp > 0 ? deltaViews / deltaImp : null,
          source: 'youtube_analytics_api'
        })
      });
    } catch (_) { }

    const newImp = (currentVariant.total_impressions || 0) + deltaImp;
    const newViews = (currentVariant.total_views || 0) + deltaViews;
    const newCtr = newImp > 0 ? newViews / newImp : null;
    const hoursLive = Math.round(((nowMs - (currentVariant.last_live_at ? new Date(currentVariant.last_live_at).getTime() : nowMs)) / 3600000) + (currentVariant.total_hours_live || 0));
    try {
      await fetch(`${supabaseUrl}/rest/v1/ab_test_variants?id=eq.${currentVariant.id}`, {
        method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          total_impressions: newImp,
          total_views: newViews,
          total_ctr: newCtr,
          total_hours_live: hoursLive
        })
      });
      // Mutate locally for winner check below
      currentVariant.total_impressions = newImp;
      currentVariant.total_views = newViews;
      currentVariant.total_ctr = newCtr;
      currentVariant.total_hours_live = hoursLive;
    } catch (_) { }
  }

  // 5. Check winner condition: all variants meet min_impressions + min_days_live
  const minImp = test.min_impressions_per_variant || 1000;
  const minHrs = (test.min_days_per_variant || 2) * 24;
  const allReady = variants.every(v => (v.total_impressions || 0) >= minImp && (v.total_hours_live || 0) >= minHrs);

  let winnerVariantId = null;
  let winnerConfidence = null;
  if (allReady) {
    // Sort by CTR desc, compare top 2
    const sorted = [...variants].sort((a, b) => (b.total_ctr || 0) - (a.total_ctr || 0));
    const a = sorted[0], b = sorted[1];
    const z = twoPropZ(a.total_views || 0, a.total_impressions || 0, b.total_views || 0, b.total_impressions || 0);
    const confidence = normalCdf(Math.abs(z));
    winnerConfidence = confidence;
    if (confidence >= (test.confidence_threshold || 0.95)) {
      winnerVariantId = a.id;
      // Mark winner
      try {
        await fetch(`${supabaseUrl}/rest/v1/ab_test_variants?id=eq.${a.id}`, {
          method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body: JSON.stringify({ is_winner: true, confidence_score: confidence })
        });
      } catch (_) { }
    }
  }

  // Abort-if-stuck safety: exceeded 7x min_days without significance -> completed_inconclusive
  const maxHours = (test.min_days_per_variant || 2) * 24 * 7;
  const totalHoursAllVariants = variants.reduce((s, v) => s + (v.total_hours_live || 0), 0);
  const shouldAbort = !winnerVariantId && totalHoursAllVariants > maxHours * variants.length;

  if (winnerVariantId) {
    // Test completed — apply winner permanently
    const winnerVariant = variants.find(v => v.id === winnerVariantId);
    let winnerApplied = false;
    let winnerApplyError = null;
    if (ytOauth && winnerVariant) {
      try {
        const getRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet&id=${test.youtube_video_id}`, {
          method: 'GET', headers: { 'Authorization': `Bearer ${ytOauth}` }
        });
        if (getRes.ok) {
          const body = await getRes.json();
          const snippet = body.items?.[0]?.snippet || {};
          if (winnerVariant.title && (test.test_type === 'title' || test.test_type === 'combined')) {
            snippet.title = winnerVariant.title.slice(0, 100);
          }
          if (!snippet.categoryId) snippet.categoryId = '22';
          const updRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet`, {
            method: 'PUT',
            headers: { 'Authorization': `Bearer ${ytOauth}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: test.youtube_video_id, snippet })
          });
          winnerApplied = updRes.ok;
          if (!updRes.ok) winnerApplyError = `winner apply: HTTP ${updRes.status}`;
          // TODO: thumbnails/set for thumbnail/combined winners
        }
      } catch (e) { winnerApplyError = e.message; }
    }

    // PATCH ab_tests — completed
    try {
      await fetch(`${supabaseUrl}/rest/v1/ab_tests?id=eq.${test.id}`, {
        method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          status: 'completed',
          winning_variant_id: winnerVariantId,
          winner_applied: winnerApplied,
          completed_at: nowIso,
          last_rotated_at: nowIso
        })
      });
    } catch (_) { }

    // Optionally promote winner onto topic
    if (winnerApplied && winnerVariant.title) {
      try {
        await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${test.topic_id}`, {
          method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body: JSON.stringify({ selected_title: winnerVariant.title })
        });
      } catch (_) { }
    }

    testResult.winner_found = true;
    testResult.winner_variant_id = winnerVariantId;
    testResult.winner_confidence = winnerConfidence;
    testResult.winner_applied = winnerApplied;
    if (winnerApplyError) testResult.errors.push(winnerApplyError);
  } else if (shouldAbort) {
    try {
      await fetch(`${supabaseUrl}/rest/v1/ab_tests?id=eq.${test.id}`, {
        method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          status: 'completed',
          completed_at: nowIso,
          last_rotated_at: nowIso,
          test_notes: `Inconclusive — exceeded ${maxHours}h without significance (confidence=${(winnerConfidence || 0).toFixed(3)})`
        })
      });
    } catch (_) { }
    testResult.aborted = true;
    testResult.winner_confidence = winnerConfidence;
  } else {
    // 6. Pick next variant — round-robin by variant_order. Prefer untested variants.
    const unlive = variants.filter(v => !v.last_live_at);
    let nextVariant;
    if (unlive.length > 0) {
      nextVariant = unlive.sort((a, b) => a.variant_order - b.variant_order)[0];
    } else {
      const currentOrder = currentVariant.variant_order;
      nextVariant = variants.find(v => v.variant_order === (currentOrder + 1) % variants.length);
    }
    if (!nextVariant || nextVariant.id === currentVariant.id) {
      testResult.errors.push('Could not pick next variant');
      results.push(testResult);
      continue;
    }

    // 7. Apply next variant to YouTube
    let nextApplied = false;
    let applyError = null;
    if (ytOauth) {
      try {
        const getRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet&id=${test.youtube_video_id}`, {
          method: 'GET', headers: { 'Authorization': `Bearer ${ytOauth}` }
        });
        if (getRes.ok) {
          const body = await getRes.json();
          const snippet = body.items?.[0]?.snippet || {};
          if (nextVariant.title && (test.test_type === 'title' || test.test_type === 'combined')) {
            snippet.title = nextVariant.title.slice(0, 100);
          }
          if (!snippet.categoryId) snippet.categoryId = '22';
          const updRes = await fetch(`https://www.googleapis.com/youtube/v3/videos?part=snippet`, {
            method: 'PUT',
            headers: { 'Authorization': `Bearer ${ytOauth}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: test.youtube_video_id, snippet })
          });
          nextApplied = updRes.ok;
          if (!updRes.ok) applyError = `rotation apply: HTTP ${updRes.status}`;
          // TODO: thumbnails/set for thumbnail/combined rotations
        } else { applyError = `videos.list: ${getRes.status}`; }
      } catch (e) { applyError = e.message; }
    } else {
      applyError = 'OAuth missing — rotation recorded in DB only';
    }

    // 8. PATCH ab_tests + variant
    try {
      await fetch(`${supabaseUrl}/rest/v1/ab_tests?id=eq.${test.id}`, {
        method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({ current_variant_id: nextVariant.id, last_rotated_at: nowIso })
      });
      await fetch(`${supabaseUrl}/rest/v1/ab_test_variants?id=eq.${nextVariant.id}`, {
        method: 'PATCH', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          last_live_at: nowIso,
          rotation_count: (nextVariant.rotation_count || 0) + 1
        })
      });
    } catch (_) { }

    testResult.rotated = true;
    testResult.from_variant_id = currentVariant.id;
    testResult.to_variant_id = nextVariant.id;
    testResult.youtube_applied = nextApplied;
    if (applyError) testResult.errors.push(applyError);
  }

  // production_logs per test
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST', headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: test.project_id,
        topic_id: test.topic_id,
        stage: 'ab_test_rotate',
        scene_number: null,
        action: testResult.winner_found ? 'winner_found' : (testResult.aborted ? 'aborted_inconclusive' : 'rotated'),
        status: testResult.errors.length ? 'partial' : 'success',
        duration_ms: 0,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { }

  results.push(testResult);
}

return [{
  json: {
    success: true,
    mode: 'rotate',
    tests_processed: tests.length,
    results,
    http_status: 200,
    via_webhook: data.via_webhook
  }
}];
